var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`티타임을 가질 시간은 아니네요. 무슨 일로 부르셨죠?`,JPN:`ティータイムではないのですね。どのようなご用件でしょうか？`,ENG:`It's too early for tea. What can I do for you?`,TWN:`現在還沒到下午茶時間呢，你找我有什麼事嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`흐음...... 종신계약이요?`,JPN:`ふうん……終身契約ですか？`,ENG:`Hmm... A lifetime contract?`,TWN:`嗯……終身契約嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`실례되는 지적일 수도 있지만, 그 계약이라는 건 저와 같이 뛰어난 재원을 일방적으로 구속하고 싶으시다는 의미로 들리네요.`,JPN:`失礼な発言かもしれませんが、その契約というものは、私のような優れた人材を一方的に拘束したいという意味に聞こえますわ。`,ENG:`With all due respect, that contract just sounds like shackles used to hold back brilliant talent like me.`,TWN:`雖然這麼說可能很失禮，但是契約這種東西，聽起來是想要單方面束縛我這種才女呢。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`애석하게도 그 제안은 받아들이기 어렵겠어요. 제가 머리를 숙일 분은 여왕 폐하뿐이거든요.`,JPN:`残念ながら、その提案はお受けできません。私が敬意を表わす方は、女王陛下だけなのですから。`,ENG:`I'm sorry, but I can't accept your offer. The only person I'm willing to bow to is Her Majesty.`,TWN:`很遺憾，這個提案我很難接受。能讓我低頭的，就只有女王陛下而已。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`하지만......`,JPN:`ですが……`,ENG:`However...`,TWN:`但是……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`개인적인 호의로 절 구속하시겠다고 하신다면, 기꺼이 협력할 용의도 있답니다.`,JPN:`もし、個人的な好意で私を拘束するつもりでしたら、喜んで協力したいと思いますわ。`,ENG:`I am willing to cooperate with you if you want to hold me back for purely personal reasons.`,TWN:`如果你是出於個人的好感，想要束縛我的話，那我很樂意和你合作。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,text:{KOREA:`자, 어쩌시겠어요?`,JPN:`いかがなさいますか？`,ENG:`Now, what's your answer?`,TWN:`那麼，你打算怎麼做？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ELIZABETH_PRYDWEN_ReinforcedA_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};